const data = $input.first().json;
const execution = data.execution;
const error = execution.error || {};
const workflow = data.workflow || {};

const now = new Date();
const jstDate = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const timestamp = jstDate.toISOString().replace('T', ' ').slice(0, 19);

const errorMessage = error.message || JSON.stringify(error);
const nodeName = (error.node && error.node.name) ? error.node.name : (execution.lastNodeExecuted || '不明');
const stack = error.stack || '';

const body = `<h2 style="color: #d32f2f;">ワークフローでエラーが発生しました</h2>
<table border="1" cellpadding="8" cellspacing="0" style="border-collapse:collapse;font-family:sans-serif;font-size:14px;">
  <tr><th style="background:#f0f0f0;">発生日時</th><td>${timestamp} (JST)</td></tr>
  <tr><th style="background:#f0f0f0;">ワークフロー</th><td>${workflow.name || '不明'} (ID: ${workflow.id || 'N/A'})</td></tr>
  <tr><th style="background:#f0f0f0;">エラー内容</th><td>${errorMessage}</td></tr>
  <tr><th style="background:#f0f0f0;">発生ノード</th><td>${nodeName}</td></tr>
  <tr><th style="background:#f0f0f0;">実行ID</th><td>${execution.id || 'N/A'}</td></tr>
  <tr><th style="background:#f0f0f0;">実行詳細</th><td><a href="${execution.url || '#'}">確認する</a></td></tr>
</table>
<br>
${stack ? '<details><summary>スタックトレース</summary><pre>' + stack + '</pre></details>' : ''}`;

return [{ json: { emailBody: body, workflowName: workflow.name || '不明' } }];

